write_file:{"path":"src/game/constants.js","content":"// 实体类型
export const ENTITY_TYPES = {
  EMPTY: 'empty',
  WALL: 'wall',
  FLAG: 'flag',
  BABA: 'baba',
  KEKE: 'keke',
  RULE_BLOCK: 'rule_block',
};

// 规则属性
export const PROPERTIES = {
  STOP: 'STOP',     // 不可穿越/不可推动
  PUSH: 'PUSH',     // 可推动
  WIN: 'WIN',       // 触碰即胜利
  YOU: 'YOU',       // 你控制的角色
};

// 玩家
export const PLAYERS = {
  A: 'A',
  B: 'B',
};

// 方向
export const DIRECTIONS = {
  UP: { x: 0, y: -1 },
  DOWN: { x: 0, y: 1 },
  LEFT: { x: -1, y: 0 },
  RIGHT: { x: 1, y: 0 },
};

// 实体图标映射
export const ENTITY_ICONS = {
  [ENTITY_TYPES.WALL]: '🧱',
  [ENTITY_TYPES.FLAG]: '🚩',
  [ENTITY_TYPES.BABA]: '🐑',
  [ENTITY_TYPES.KEKE]: '🐱',
  [ENTITY_TYPES.RULE_BLOCK]: '📜',
  [ENTITY_TYPES.EMPTY]: '',
};

// 属性颜色映射
export const PROPERTY_COLORS = {
  [PROPERTIES.STOP]: '#e74c3c',   // 红色
  [PROPERTIES.PUSH]: '#f39c12',   // 橙色
  [PROPERTIES.WIN]: '#2ecc71',    // 绿色
  [PROPERTIES.YOU]: '#3498db',    // 蓝色
};

// 属性中文名
export const PROPERTY_NAMES = {
  [PROPERTIES.STOP]: '停止',
  [PROPERTIES.PUSH]: '推动',
  [PROPERTIES.WIN]: '胜利',
  [PROPERTIES.YOU]: '是你',
};
"}

write_file:{"path":"src/game/GameState.js","content":"import { ENTITY_TYPES, PROPERTIES, PLAYERS, DIRECTIONS } from './constants.js';
import { LEVELS } from './Levels.js';

/**
 * 核心游戏状态管理
 * 管理双视角规则、移动、揭示等核心逻辑
 */
class GameState {
  constructor(levelIndex = 0) {
    this.loadLevel(levelIndex);
    this.currentPlayer = PLAYERS.A;
    this.revealTokens = 3;
    this.winner = null;
    this.turnCount = 0;
    this.revealHistory = [];
    this.moveHistory = [];
    this.sideEffects = [];
  }

  loadLevel(levelIndex) {
    const level = LEVELS[levelIndex];
    this.level = level;
    this.width = level.width;
    this.height = level.height;
    this.grid = level.grid.map(row => [...row]);
    this.playerAPerspective = { ...level.playerA.perspective };
    this.playerBPerspective = { ...level.playerB.perspective };
    this.babaPos = { ...level.playerA.babaPos };
    this.kekePos = { ...level.playerA.kekePos };
    this.revealTokens = level.revealTokens;
    this.currentPlayer = PLAYERS.A;
    this.winner = null;
    this.turnCount = 0;
    this.revealHistory = [];
    this.moveHistory = [];
    this.sideEffects = [];
  }

  getPropertyForPlayer(player, entityType, x, y) {
    const key = `${x}-${y}`;
    const perspective = player === PLAYERS.A ? this.playerAPerspective : this.playerBPerspective;
    return perspective[key] || null;
  }

  canPush(player, x, y) {
    const entity = this.grid[y]?.[x];
    if (!entity || entity === ENTITY_TYPES.EMPTY) return false;
    if (entity !== ENTITY_TYPES.WALL && entity !== ENTITY_TYPES.RULE_BLOCK) return false;
    const property = this.getPropertyForPlayer(player, entity, x, y);
    return property === PROPERTIES.PUSH;
  }

  canMoveTo(player, x, y) {
    if (x < 0 || x >= this.width || y < 0 || y >= this.height) return false;
    const entity = this.grid[y][x];
    if (!entity || entity === ENTITY_TYPES.EMPTY) return true;
    if (entity === ENTITY_TYPES.WALL || entity === ENTITY_TYPES.RULE_BLOCK) {
      const property = this.getPropertyForPlayer(player, entity, x, y);
      if (property === PROPERTIES.STOP) return false;
      if (property === PROPERTIES.PUSH) return true;
      return false;
    }
    if (entity === ENTITY_TYPES.FLAG) {
      const property = this.getPropertyForPlayer(player, entity, x, y);
      if (property === PROPERTIES.WIN) return 'win';
      return true;
    }
    if (entity === ENTITY_TYPES.BABA || entity === ENTITY_TYPES.KEKE) return false;
    return true;
  }

  getCurrentPlayerPos() {
    return this.currentPlayer === PLAYERS.A ? { ...this.babaPos } : { ...this.kekePos };
  }

  movePlayer(direction) {
    if (this.winner) return { success: false, reason: '游戏已结束' };
    const player = this.currentPlayer;
    const pos = this.getCurrentPlayerPos();
    const newX = pos.x + direction.x;
    const newY = pos.y + direction.y;
    if (newX < 0 || newX >= this.width || newY < 0 || newY >= this.height) {
      return { success: false, reason: '超出边界' };
    }
    const targetEntity = this.grid[newY][newX];
    if (!targetEntity || targetEntity === ENTITY_TYPES.EMPTY) {
      this._movePlayerTo(player, pos, newX, newY);
      this._checkWin(player);
      this._switchTurn();
      return { success: true, moved: true, action: '移动' };
    }
    if (targetEntity === ENTITY_TYPES.WALL || targetEntity === ENTITY_TYPES.RULE_BLOCK) {
      const property = this.getPropertyForPlayer(player, targetEntity, newX, newY);
      if (property === PROPERTIES.STOP) {
        return { success: false, reason: `你眼中的${ENTITY_TYPES.WALL === targetEntity ? '墙' : '规则方块'}是"停止"，无法通过` };
      }
      if (property === PROPERTIES.PUSH) {
        const pushX = newX + direction.x;
        const pushY = newY + direction.y;
        if (pushX < 0 || pushX >= this.width || pushY < 0 || pushY >= this.height) {
          return { success: false, reason: '推动后超出边界' };
        }
        if (this.grid[pushY][pushX] !== ENTITY_TYPES.EMPTY) {
          return { success: false, reason: '推动目标位置被占用' };
        }
        this.grid[pushY][pushX] = targetEntity;
        this.grid[newY][newX] = ENTITY_TYPES.EMPTY;
        this._movePlayerTo(player, pos, newX, newY);
        this._syncPerspectiveAfterPush(targetEntity, newX, newY, pushX, pushY);
        this._checkWin(player);
        this._switchTurn();
        return { success: true, moved: true, action: '推动' };
      }
    }
    if (targetEntity === ENTITY_TYPES.FLAG) {
      const property = this.getPropertyForPlayer(player, targetEntity, newX, newY);
      if (property === PROPERTIES.WIN) {
        this.winner = player;
        return { success: true, moved: true, action: '胜利！', winner: player };
      }
      const pushX = newX + direction.x;
      const pushY = newY + direction.y;
      if (pushX >= 0 && pushX < this.width && pushY >= 0 && pushY < this.height 
          && (!this.grid[pushY][pushX] || this.grid[pushY][pushX] === ENTITY_TYPES.EMPTY)) {
        this.grid[pushY][pushX] = ENTITY_TYPES.FLAG;
        this.grid[newY][newX] = ENTITY_TYPES.EMPTY;
        this._movePlayerTo(player, pos, newX, newY);
        this._syncPerspectiveAfterPush(ENTITY_TYPES.FLAG, newX, newY, pushX, pushY);
        this._switchTurn();
        return { success: true, moved: true, action: '推动旗帜' };
      }
      return { success: false, reason: '无法推动旗帜' };
    }
    return { success: false, reason: '目标位置无法移动' };
  }

  _movePlayerTo(player, oldPos, newX, newY) {
    const entity = player === PLAYERS.A ? ENTITY_TYPES.BABA : ENTITY_TYPES.KEKE;
    this.grid[oldPos.y][oldPos.x] = ENTITY_TYPES.EMPTY;
    this.grid[newY][newX] = entity;
    if (player === PLAYERS.A) {
      this.babaPos = { x: newX, y: newY };
    } else {
      this.kekePos = { x: newX, y: newY };
    }
    this.turnCount++;
  }

  _syncPerspectiveAfterPush(entityType, fromX, fromY, toX, toY) {
    const oldKey = `${fromX}-${fromY}`;
    const newKey = `${toX}-${toY}`;
    if (this.playerAPerspective[oldKey] !== undefined) {
      this.playerAPerspective[newKey] = this.playerAPerspective[oldKey];
      delete this.playerAPerspective[oldKey];
    }
    if (this.playerBPerspective[oldKey] !== undefined) {
      this.playerBPerspective[newKey] = this.playerBPerspective[oldKey];
      delete this.playerBPerspective[oldKey];
    }
  }

  _checkWin(player) {
    // 胜利条件在 movePlayer 中检查
  }

  _switchTurn() {
    this.currentPlayer = this.currentPlayer === PLAYERS.A ? PLAYERS.B : PLAYERS.A;
  }

  useRevealToken(sourcePlayer, targetPlayer, x, y) {
    if (this.revealTokens <= 0) return { success: false, reason: '揭示令牌已用完' };
    if (this.currentPlayer !== sourcePlayer) return { success: false, reason: '不是你的回合' };
    const entity = this.grid[y]?.[x];
    if (!entity || entity === ENTITY_TYPES.EMPTY) return { success: false, reason: '该位置没有实体' };
    const property = this.getPropertyForPlayer(sourcePlayer, entity, x, y);
    if (!property) return { success: false, reason: '该实体在你眼中没有特殊属性' };
    this.revealTokens--;
    this.revealHistory.push({ sourcePlayer, targetPlayer, x, y, entity, property });
    return { success: true, action: '揭示', data: { entity, property, x, y } };
  }

  getSnapshot() {
    return {
      grid: this.grid.map(row => [...row]),
      babaPos: { ...this.babaPos },
      kekePos: { ...this.kekePos },
      currentPlayer: this.currentPlayer,
      revealTokens: this.revealTokens,
      winner: this.winner,
      turnCount: this.turnCount,
      moveHistory: [...this.moveHistory],
      revealHistory: [...this.revealHistory],
    };
  }

  getPerspectiveView(player) {
    const view = {
      grid: this.grid.map(row => [...row]),
      properties: {},
    };
    const perspective = player === PLAYERS.A ? this.playerAPerspective : this.playerBPerspective;
    for (let y = 0; y < this.height; y++) {
      for (let x = 0; x < this.width; x++) {
        const entity = this.grid[y][x];
        if (entity && entity !== ENTITY_TYPES.EMPTY) {
          const key = `${x}-${y}`;
          if (perspective[key]) {
            view.properties[key] = perspective[key];
          }
        }
      }
    }
    return view;
  }
}

export default GameState;
"}

