write_file:{"path":"/Users/jingslunt/workspace/src/ui/BoardRenderer.js","content":"import { ENTITY, DIRECTION, PROPERTY, CARDINALS } from '../game/constants.js';

/**
 * BoardRenderer — renders the grid DOM for a specific player's perspective.
 * Each player sees only items they are "adjacent to" or have been revealed.
 */
export class BoardRenderer {
  constructor(playerViewId, stateAccessor) {
    this.container = document.getElementById(playerViewId);
    this.stateAccessor = stateAccessor; // () => GameState
    this.gridEl = null;
    this.onCellClick = null; // callback( { player, x, y } )
  }

  buildGrid() {
    const state = this.stateAccessor();
    const grid = state.grid;
    this.gridEl = document.createElement('div');
    this.gridEl.className = 'grid';
    this.gridEl.style.gridTemplateColumns = `repeat(${grid.width}, 1fr)`;
    this.gridEl.style.gridTemplateRows = `repeat(${grid.height}, 1fr)`;

    for (let y = 0; y < grid.height; y++) {
      for (let x = 0; x < grid.width; x++) {
        const cell = document.createElement('div');
        cell.className = 'grid-cell';
        cell.dataset.x = x;
        cell.dataset.y = y;
        cell.addEventListener('click', () => {
          if (this.onCellClick) {
            const pid = this.container.id === 'player-a-grid' ? 'A' : 'B';
            this.onCellClick({ player: pid, x, y });
          }
        });
        this.gridEl.appendChild(cell);
      }
    }

    // Replace existing grid
    this.container.innerHTML = '';
    this.container.appendChild(this.gridEl);
  }

  /**
   * Refresh cell contents based on current state and visibility map.
   * @param {Set<string>} visibleSet — keys like "x,y"
   * @param {{x?:number,y?:number}} selection
   */
  render(visibleSet, selection = {}) {
    const state = this.stateAccessor();
    const grid = state.grid;
    const cells = this.gridEl.querySelectorAll('.grid-cell');
    const pid = this.container.id === 'player-a-grid' ? 'A' : 'B';

    cells.forEach(cell => {
      const x = parseInt(cell.dataset.x);
      const y = parseInt(cell.dataset.y);
      const key = `${x},${y}`;
      cell.innerHTML = '';

      // Selection highlight
      cell.classList.toggle('selected',
        selection.x === x && selection.y === y);

      // Hidden cell
      if (!visibleSet.has(key)) {
        cell.classList.add('hidden');
        cell.title = '未探索区域';
        return;
      }

      cell.classList.remove('hidden');
      const cellData = grid.cells[y][x];
      cell.title = '';

      // Render entities
      if (cellData.length === 0) {
        cell.innerHTML = '<span style="color:#333">·</span>';
        cell.title = '空地';
      } else {
        // Primary entity icon
        const entity = cellData[0];
        cell.innerHTML = `<span class="cell-icon">${entity.icon}</span>`;

        // If multiple, show count
        if (cellData.length > 1) {
          const badge = document.createElement('span');
          badge.className = 'cell-rule-indicator';
          badge.textContent = `×${cellData.length}`;
          cell.appendChild(badge);
        }

        // Build tooltip
        cell.title = cellData.map(e =>
          `${e.name} [${e.propertyName}]`
        ).join(', ');
      }
    });
  }

  showWinOverlay(message) {
    // Remove previous overlay
    const prev = document.querySelector('.win-overlay');
    if (prev) prev.remove();

    const overlay = document.createElement('div');
    overlay.className = 'win-overlay';
    overlay.innerHTML = `
      <div class="win-dialog">
        <h2>🎉 胜利！</h2>
        <p>${message}</p>
        <button id="win-restart">重新开始</button>
      </div>
    `;
    document.body.appendChild(overlay);

    document.getElementById('win-restart').addEventListener('click', () => {
      overlay.remove();
      window.dispatchEvent(new CustomEvent('game-restart'));
    });
  }
}"}

write_file:{"path":"/Users/jingslunt/workspace/src/ui/InputHandler.js","content":"import { DIRECTION, PLAYER } from '../game/constants.js';

const KEY_MAP_PLAYER_A = {
  ArrowUp:    DIRECTION.UP,
  ArrowDown:  DIRECTION.DOWN,
  ArrowLeft:  DIRECTION.LEFT,
  ArrowRight: DIRECTION.RIGHT,
  w: DIRECTION.UP,
  s: DIRECTION.DOWN,
  a: DIRECTION.LEFT,
  d: DIRECTION.RIGHT,
};

const KEY_MAP_PLAYER_B = {
  i: DIRECTION.UP,
  k: DIRECTION.DOWN,
  j: DIRECTION.LEFT,
  l: DIRECTION.RIGHT,
};

/**
 * InputHandler captures keyboard events and maps them to game actions.
 */
export class InputHandler {
  constructor(onMove, onReveal, onWait, onUndo) {
    this.onMove = onMove;     // (player, direction)
    this.onReveal = onReveal; // (player)
    this.onWait = onWait;     // (player)
    this.onUndo = onUndo;     // ()
    this._handler = this._handleKey.bind(this);
  }

  attach() {
    window.addEventListener('keydown', this._handler);
  }

  detach() {
    window.removeEventListener('keydown', this._handler);
  }

  _handleKey(e) {
    // Don't capture if focus is in an input
    if (e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT' ||
        e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;

    // Global undo
    if (e.ctrlKey && e.key === 'z') {
      e.preventDefault();
      this.onUndo();
      return;
