      this.onReveal(PLAYER.B);
      return;
    }

    // Wait actions
    if (e.key === 'e') {
      e.preventDefault();
      this.onWait(PLAYER.A);
      return;
    }
    if (e.key === 'o') {
      e.preventDefault();
      this.onWait(PLAYER.B);
      return;
    }

    // Movement
    const dirA = KEY_MAP_PLAYER_A[e.key];
    if (dirA !== undefined) {
      e.preventDefault();
      this.onMove(PLAYER.A, dirA);
      return;
