 * RevealSystem manages the reveal token economy and visibility maps.
 * Each player starts with 3 tokens. 1 token = 1 turn of revealing info.
 */
export class RevealSystem {
  constructor() {
    // Tokens per player
    this.tokens = { A: 3, B: 3 };
    // Which cells each player can see: { A: Set<'x,y'>, B: Set<'x,y'> }
    this.visible = {
      A: new Set(),
      B: new Set(),
    };
  }

  reset() {
    this.tokens = { A: 3, B: 3 };
    this.visible.A.clear();
    this.visible.B.clear();
  }

  /**
   * Compute initial visible cells based on player positions and "adjacent" range.
   * Player can see: their own cell + 4 orthogonally adjacent cells.
   */
  computeVisibility(player, px, py, grid) {
    const set = this.visible[player];
    set.add(`${px},${py}`);
    const adjacents = [
      [px, py - 1], [px, py + 1],
      [px - 1, py], [px + 1, py],
    ];
    for (const [ax, ay] of adjacents) {
      if (ax >= 0 && ax < grid.width && ay >= 0 && ay < grid.height) {
        set.add(`${ax},${ay}`);
      }
    }
  }

  /**
   * Reveal a specific cell (using a token).
   * Returns the revealed data, or null if no tokens left.
   */
  revealCell(player, x, y, grid) {
    if (this.tokens[player] <= 0) return null;
    if (x < 0 || x >= grid.width || y < 0 || y >= grid.height) return null;

    this.tokens[player]--;
    const key = `${x},${y}`;
    this.visible[player].add(key);

    const cellData = grid.cells[y][x];
    return {
      x, y,
      entities: cellData,
      tokensLeft: this.tokens[player],
    };
  }

  /**
   * Reveal a 3×3 area centered on (cx,cy). Costs 1 token.
   */
  revealArea(player, cx, cy, grid) {
    if (this.tokens[player] <= 0) return [];
    this.tokens[player]--;

    const revealed = [];
    for (let dy = -1; dy <= 1; dy++) {
      for (let dx = -1; dx <= 1; dx++) {
        const nx = cx + dx;
        const ny = cy + dy;
        if (nx >= 0 && nx < grid.width && ny >= 0 && ny < grid.height) {
          const key = `${nx},${ny}`;
          if (!this.visible[player].has(key)) {
            this.visible[player].add(key);
            revealed.push({ x: nx, y: ny, entities: grid.cells[ny][nx] });
          }
        }
      }
    }
    return revealed;
  }
}"}

write_file:{"content":"import { GameState } from '../game/GameState.js';
import { GameEngine } from '../game/GameEngine.js';
import { parseRules } from '../game/DSLParser.js';
import { BoardRenderer } from './BoardRenderer.js';
import { RevealSystem } from './RevealSystem.js';
import { InputHandler } from './InputHandler.js';
import { MessageLog } from './MessageLog.js';
import { PLAYER, DIRECTION } from '../game/constants.js';

const PLAYER_NAMES = { A: '🔵 玩家A', B: '🟠 玩家B' };
const DIR_NAMES = {
  [DIRECTION.UP]: '↑上',
  [DIRECTION.DOWN]: '↓下',
  [DIRECTION.LEFT]: '←左',
  [DIRECTION.RIGHT]: '→右',
};

export class Game {
  constructor() {
    this.state = null;
    this.engine = null;
    this.reveal = new RevealSystem();
    this.log = new MessageLog('message-log');

    this.rendererA = new BoardRenderer('player-a-grid', () => this.state);
    this.rendererB = new BoardRenderer('player-b-grid', () => this.state);

    this.input = new InputHandler(
      (p, d) => this.handleMove(p, d),
      (p) => this.handleReveal(p),
      (p) => this.handleWait(p),
      () => this.handleUndo()
    );

    this.selectedCell = { A: null, B: null };

    // Bind cell click
    this.rendererA.onCellClick = (pos) => this.onCellClick('A', pos);
    this.rendererB.onCellClick = (pos) => this.onCellClick('B', pos);

    // Restart listener
    window.addEventListener('game-restart', () => this.restart());

    // Bind buttons
    document.getElementById('btn-restart').addEventListener('click', () => this.restart());
    document.getElementById('map-select').addEventListener('change', (e) => {
      if (e.target.value) this.loadMap(e.target.value);
    });
  }

  start() {
    this.loadMap('5x5-default');
    this.input.attach();
  }

  loadMap(mapId) {
    const rulesEl = document.getElementById('rules-source');
    let rulesText = '';

    // Try to load from a data attribute or embedded script
    const scriptEl = document.getElementById(`map-${mapId}`);
    if (scriptEl) {
      rulesText = scriptEl.textContent.trim();
    }

    if (!rulesText) {
      // Fallback: generate a default ruleset for the map
      rulesText = this.getDefaultRules(mapId);
    }

    const rules = parseRules(rulesText);
    if (!rules) {
      this.log.add('⚠️ 规则解析失败', 'system');
      return;
    }

    this.state = new GameState(rules);
    this.engine = new GameEngine(this.state, rules);
    this.reveal.reset();

    // Initialize visibility for both players
    this.reveal.computeVisibility('A', this.state.players.A.x, this.state.players.A.y, this.state.grid);
    this.reveal.computeVisibility('B', this.state.players.B.x, this.state.players.B.y, this.state.grid);

    // Build grids
    this.rendererA.buildGrid();
    this.rendererB.buildGrid();

    this.selectedCell = { A: null, B: null };
    this.updateUI();

    this.log.clear();
    this.log.add(`🗺️ 加载地图: ${mapId}`, 'system');
    this.log.add(`${PLAYER_NAMES.A} 起始位置: (${this.state.players.A.x}, ${this.state.players.A.y})`, 'system');
    this.log.add(`${PLAYER_NAMES.B} 起始位置: (${this.state.players.B.x}, ${this.state.players.B.y})`, 'system');
    this.log.add('提示：移动到相邻格可揭示周围信息；按 Q/E 揭示A玩家区域，U/O 揭示B玩家区域', 'system');
  }

  getDefaultRules(mapId) {
    const [width, height] = mapId.split('-')[0].split('x').map(Number);
    // Generate simple rules: each player starts in corners, random win items placed
    return `# Default rules for ${mapId}
GRID ${width} ${height}
PLAYER_A_START 1 1
PLAYER_B_START ${width} ${height}
WIN_CONDITION COLLECT_TARGET
`;
  }

  onCellClick(player, { x, y }) {
    // Reveal cell using a token
    const result = this.reveal.revealCell(player, x, y, this.state.grid);
    if (!result) {
      this.log.add(`${PLAYER_NAMES[player]} 没有揭示次数了`, 'system');
      return;
    }

    this.selectedCell[player] = { x, y };
    const entities = result.entities;
    const desc = entities.length > 0
      ? entities.map(e => `${e.name}[${e.propertyName}]`).join(', ')
      : '空地';
    this.log.addReveal(PLAYER_NAMES[player], `(${x},${y}) → ${desc} (剩余${result.tokensLeft}次)`);
    this.updateUI();
  }

  handleMove(player, direction) {
    if (!this.state || this.state.gameOver) return;

    const result = this.engine.movePlayer(player, direction);
    if (!result.success) {
      this.log.add(`${PLAYER_NAMES[player]} ${result.reason}`, 'system');
      return;
    }

    const { x, y } = this.state.players[player];
    this.reveal.computeVisibility(player, x, y, this.state.grid);
    this.log.addMove(PLAYER_NAMES[player], DIR_NAMES[direction]);

    // Check for win
    if (result.gameOver) {
      this.onWin(result);
      return;
    }

    this.updateUI();
  }

  handleReveal(player) {
    if (!this.state || this.state.gameOver) return;

    const pos = this.state.players[player];
    const result = this.reveal.revealArea(player, pos.x, pos.y, this.state.grid);
    if (result.length === 0) {
      this.log.add(`${PLAYER_NAMES[player]} 没有揭示次数了`, 'system');
      return;
    }

    const desc = result.map(r =>
      r.entities.length > 0
        ? r.entities.map(e => e.name).join('+')
        : '空地'
    ).join(', ');
    this.log.addReveal(PLAYER_NAMES[player], `周围: ${desc}`);
    this.updateUI();
  }

  handleWait(player) {
    if (!this.state || this.state.gameOver) return;
    this.log.addWait(PLAYER_NAMES[player]);
    // Waiting does nothing mechanically, just passes turn insight
  }

  handleUndo() {
    if (!this.state || !this.engine) return;
    const success = this.engine.undoLastMove();
    if (success) {
      this.log.add('↩️ 撤销上一步', 'system');
      // Recompute visibility
      this.reveal.computeVisibility('A', this.state.players.A.x, this.state.players.A.y, this.state.grid);
      this.reveal.computeVisibility('B', this.state.players.B.x, this.state.players.B.y, this.state.grid);
    } else {
      this.log.add('无可撤销步骤', 'system');
    }
    this.updateUI();
  }

  onWin(result) {
    const playerName = PLAYER_NAMES[result.winner];
    this.log.addWin(`${playerName} 获胜！`);
    this.rendererA.showWinOverlay(`${playerName} 获胜！`);
    this.state.gameOver = true;
    this.updateUI();
  }

  updateUI() {
    if (!this.state) return;

    // Render both grids
    this.rendererA.render(this.reveal.visible.A, this.selectedCell.A || {});
    this.rendererB.render(this.reveal.visible.B, this.selectedCell.B || {});

    // Update tokens display
    document.getElementById('reveal-tokens').textContent =
      `🔎 A:${this.reveal.tokens.A} B:${this.reveal.tokens.B}`;

    // Update info panels
    const infoA = document.getElementById('info-a');
    const infoB = document.getElementById('info-b');
    if (infoA && this.state.players.A) {
      const pa = this.state.players.A;
      const cellData = this.state.grid.cells[pa.y][pa.x];
      const entities = cellData.map(e => `${e.icon} ${e.name}[${e.propertyName}]`).join(', ') || '空地';
      infoA.innerHTML = `
        <div class="current-turn">📍 位置: (${pa.x}, ${pa.y})</div>
        <div>当前位置: ${entities}</div>
        <div>揭示次数: ${this.reveal.tokens.A}</div>
      `;
    }
    if (infoB && this.state.players.B) {
      const pb = this.state.players.B;
      const cellData = this.state.grid.cells[pb.y][pb.x];
      const entities = cellData.map(e => `${e.icon} ${e.name}[${e.propertyName}]`).join(', ') || '空地';
      infoB.innerHTML = `
        <div class="current-turn">📍 位置: (${pb.x}, ${pb.y})</div>
        <div>当前位置: ${entities}</div>
        <div>揭示次数: ${this.reveal.tokens.B}</div>
      `;
    }

    // Highlight active player view (both always active in this co-op/parallel exploration)
    document.getElementById('view-a').classList.toggle('active-turn', !this.state.gameOver);
    document.getElementById('view-b').classList.toggle('active-turn', !this.state.gameOver);
  }

  restart() {
    this.loadMap(document.getElementById('map-select').value || '5x5-default');
  }
}","path":"/Users/jingslunt/workspace/src/ui/Game.js"}

