    this.playerBPerspective = { ...level.playerB.perspective };
    this.babaPos = { ...level.playerA.babaPos };
    this.kekePos = { ...level.playerA.kekePos };
    this.revealTokens = level.revealTokens;
    this.currentPlayer = PLAYERS.A;
    this.winner = null;
    this.turnCount = 0;
    this.revealHistory = [];
    this.moveHistory = [];
    this.sideEffects = [];
