  canPush(player, x, y) {
    const entity = this.grid[y]?.[x];
    if (!entity || entity === ENTITY_TYPES.EMPTY) return false;
    if (entity !== ENTITY_TYPES.WALL && entity !== ENTITY_TYPES.RULE_BLOCK) return false;
