    if (entity === ENTITY_TYPES.WALL || entity === ENTITY_TYPES.RULE_BLOCK) {
      const property = this.getPropertyForPlayer(player, entity, x, y);
      if (property === PROPERTIES.STOP) return false;
      if (property === PROPERTIES.PUSH) return true;
