write_file:{"path":"src/game/GameState.js","content":"/**
 * 游戏状态管理器 - 双盲模式
 */

export class GameState {
  constructor(width = 20, height = 15) {
    this.width = width;
    this.height = height;

    // 玩家位置
    this.players = {
      A: { x: 0, y: 0 },
      B: { x: 0, y: 0 }
    };

    // 网格：cells[y][x] = { terrain, entities[], revealedTo[], rules[] }
    this.grid = {
      width,
      height,
      cells: this._createEmptyGrid()
    };

    // 规则系统（从规则块解析）
    this.rules = {
      // e.g., { baba: ['push'], wall: ['stop'], flag: ['win'] }
    };

    // 消息日志
    this.messages = [];

    // 当前玩家
    this.currentPlayer = 'A';

    // 游戏状态
    this.gameOver = false;
    this.winner = null;
    this.levelNumber = 0;
  }

  _createEmptyGrid() {
    const cells = [];
    for (let y = 0; y < this.height; y++) {
      cells[y] = [];
      for (let x = 0; x < this.width; x++) {
        cells[y][x] = {
          terrain: 'empty',
          entities: [],
          revealedTo: [],
          rules: []
        };
      }
    }
    return cells;
  }

  /**
   * 从关卡数据初始化状态
   */
  initFromLevel(levelData) {
    // 重置
    this.grid.cells = this._createEmptyGrid();
    this.rules = {};
    this.messages = [];
    this.gameOver = false;
    this.winner = null;

    if (!levelData) return;

    const { tiles, rules } = levelData;

    // 放置图块
    if (tiles) {
      for (const tile of tiles) {
        const { x, y, type, player } = tile;
        if (x >= 0 && x < this.width && y >= 0 && y < this.height) {
          const cell = this.grid.cells[y][x];

          if (type === 'wall') {
            cell.terrain = 'wall';
          } else if (type === 'baba' || type === 'keke') {
            cell.entities.push({ type, player: player || null });
            if (player) {
              this.players[player].x = x;
              this.players[player].y = y;
            }
          } else if (type === 'flag') {
            cell.entities.push({ type: 'flag' });
          } else if (type === 'rule_block') {
            cell.entities.push({ type: 'rule_block' });
          }
        }
      }
    }

    // 初始规则
    if (rules) {
      this.rules = { ...rules };
    }

    // 初始可见性：每个玩家只能看到周围3x3区域
    this._updateVisibility();
  }

  /**
   * 更新可见性
   */
  _updateVisibility() {
    // 清除所有可见性
    for (let y = 0; y < this.height; y++) {
      for (let x = 0; x < this.width; x++) {
        this.grid.cells[y][x].revealedTo = [];
      }
    }

    // 为每个玩家揭示视距内的格子
    for (const playerId of ['A', 'B']) {
      const { x, y } = this.players[playerId];
      const visionRange = 2; // 可见距离

      for (let dy = -visionRange; dy <= visionRange; dy++) {
        for (let dx = -visionRange; dx <= visionRange; dx++) {
          const nx = x + dx;
          const ny = y + dy;
          if (nx >= 0 && nx < this.width && ny >= 0 && ny < this.height) {
            // 视线检查：简化版，忽略墙壁遮挡
            this.grid.cells[ny][nx].revealedTo.push(playerId);
          }
        }
      }
    }
  }

  /**
   * 移动玩家
   */
  movePlayer(playerId, direction) {
    if (this.gameOver) return null;

    const player = this.players[playerId];
    const { x: dx, y: dy } = direction;
    const newX = player.x + dx;
    const newY = player.y + dy;

    // 边界检查
    if (newX < 0 || newX >= this.width || newY < 0 || newY >= this.height) {
      return null;
    }

    const cell = this.grid.cells[newY][newX];

    // 地形阻挡
    if (cell.terrain === 'wall') {
      return null;
    }

    // 实体交互
    let moved = true;
    for (const entity of cell.entities) {
      const props = this.rules[entity.type] || [];

      if (props.includes('stop')) {
        moved = false;
        break;
      }

      if (props.includes('win')) {
        this.gameOver = true;
        this.winner = playerId;
        this.messages.push({ type: 'win', text: `玩家 ${playerId} 获胜！` });
      }

      if (props.includes('push')) {
        // 推动物体
        const pushedX = newX + dx;
        const pushedY = newY + dy;
        if (pushedX >= 0 && pushedX < this.width && pushedY >= 0 && pushedY < this.height) {
          const pushTarget = this.grid.cells[pushedY][pushedX];
          if (pushTarget.terrain !== 'wall' && pushTarget.entities.length === 0) {
            // 移动被推物体
            const idx = cell.entities.indexOf(entity);
            if (idx > -1) cell.entities.splice(idx, 1);
            pushTarget.entities.push(entity);
          } else {
            moved = false;
            break;
          }
        } else {
          moved = false;
          break;
        }
      }
    }

    if (!moved) return null;

    // 执行移动
    const oldCell = this.grid.cells[player.y][player.x];
    const playerEntity = oldCell.entities.find(e => e.player === playerId);
    if (playerEntity) {
      const idx = oldCell.entities.indexOf(playerEntity);
      if (idx > -1) oldCell.entities.splice(idx, 1);
      cell.entities.push(playerEntity);
    }

    player.x = newX;
    player.y = newY;

    // 更新可见性
    this._updateVisibility();

    this.messages.push({
      type: 'move',
      text: `玩家 ${playerId} 向 ${direction.name} 移动`,
      player: playerId,
      from: { x: player.x - dx, y: player.y - dy },
      to: { x: newX, y: newY }
    });

    return {
      playerId,
      from: { x: player.x - dx, y: player.y - dy },
      to: { x: newX, y: newY },
      pushed: false
    };
  }

  /**
   * 切换当前玩家
   */
  switchPlayer() {
    this.currentPlayer = this.currentPlayer === 'A' ? 'B' : 'A';
    this.messages.push({ type: 'system', text: `轮到玩家 ${this.currentPlayer}` });
  }

  /**
   * 检查是否获胜
   */
  checkWin() {
    return this.gameOver ? this.winner : null;
  }

  /**
   * 获取某个玩家的可见格子（用于渲染）
   */
  getVisibleGrid(playerId) {
    const visible = [];
    for (let y = 0; y < this.height; y++) {
      visible[y] = [];
      for (let x = 0; x < this.width; x++) {
        const cell = this.grid.cells[y][x];
        if (cell.revealedTo.includes(playerId)) {
          visible[y][x] = {
            terrain: cell.terrain,
            entities: [...cell.entities],
            rules: cell.rules
          };
        } else {
          visible[y][x] = null; // 未揭示
        }
      }
    }
    return visible;
  }

  /**
   * 序列化状态（用于网络传输）
   */
  serialize() {
    return JSON.stringify({
      width: this.width,
      height: this.height,
      players: this.players,
      grid: this.grid,
      rules: this.rules,
      currentPlayer: this.currentPlayer,
      gameOver: this.gameOver,
      winner: this.winner,
      levelNumber: this.levelNumber
    });
  }

  /**
   * 反序列化状态
   */
  static deserialize(json) {
    const data = JSON.parse(json);
    const state = new GameState(data.width, data.height);
    state.players = data.players;
    state.grid = data.grid;
    state.rules = data.rules;
    state.currentPlayer = data.currentPlayer;
    state.gameOver = data.gameOver;
    state.winner = data.winner;
    state.levelNumber = data.levelNumber;
    return state;
  }
}

export default GameState;
"}

write_file:{"file_path":"src/game/DSLParser.js","content":"/**
 * DSL parser for game behavior/level scripting.
 * Parses rule definitions such as:
 *   BABA IS PUSH
 *   WALL IS STOP
 *   FLAG IS WIN
 *   KEKE IS YOU
 * Lines starting with # are comments.
 */
export class DSLParser {
  constructor(source) {
    this.source = source;
  }

  parse() {
    const commands = [];
    const lines = this.source.split('\n');
    for (let line of lines) {
      line = line.trim();
      // Skip empty lines and comments
      if (line === '' || line.startsWith('#')) continue;

      // Split into tokens by whitespace
      const parts = line.split(/\s+/);
      if (parts.length < 3) continue;

      const entity = parts[0].toUpperCase();
      const connector = parts[1].toLowerCase();
      const property = parts[2].toUpperCase();

      // Accept "IS" or "HAS" as connectors
      if (connector === 'is' || connector === 'has') {
        commands.push({ entity, property });
      }
      // Future: could support other command types here
    }
    return {
      type: 'script',
      commands,
    };
  }

  static fromString(input) {
    const parser = new DSLParser(input);
    return parser.parse();
  }
}
