write_file:{"path":"src/ui/BoardRenderer.js","content":"import { PLAYER } from '../game/constants.js';

/**
 * BoardRenderer draws the game grid to the DOM.
 */
export class BoardRenderer {
  constructor(gameState) {
    this.state = gameState;
    this.grid = null;
  }

  createGrid(containerId) {
    const container = document.getElementById(containerId);
    container.innerHTML = '';
    this.grid = document.createElement('div');
    this.grid.className = 'board-grid';
    this.grid.style.gridTemplateColumns = `repeat(${this.state.width}, 1fr)`;
    this.grid.style.gridTemplateRows = `repeat(${this.state.height}, 1fr)`;
    container.appendChild(this.grid);

    // Create cells
    for (let y = 0; y < this.state.height; y++) {
      for (let x = 0; x < this.state.width; x++) {
        const cell = document.createElement('div');
        cell.className = 'cell';
        cell.dataset.x = x;
        cell.dataset.y = y;
        this.grid.appendChild(cell);
      }
    }
  }

  render() {
    const cells = this.grid.children;
    for (let y = 0; y < this.state.height; y++) {
      for (let x = 0; x < this.state.width; x++) {
        const cell = cells[y * this.state.width + x];
        this.renderCell(cell, x, y);
      }
    }
  }

  renderCell(cell, x, y) {
    // Check visibility for current player (or both players in full reveal mode)
    const visibleA = this.state.isRevealedTo(x, y, PLAYER.A);
    const visibleB = this.state.isRevealedTo(x, y, PLAYER.B);
    const isVisible = visibleA || visibleB;

    if (!isVisible) {
      cell.classList.add('hidden');
      cell.innerHTML = '';
      cell.title = '';
      return;
    }

    cell.classList.remove('hidden');
    const cellObj = this.state.grid.cells[y][x];
    const entities = cellObj.entities || [];

    // Terrain styling
    cell.className = 'cell';
    if (cellObj.terrain === 'wall') {
      cell.classList.add('cell-wall');
    } else if (cellObj.terrain === 'water') {
      cell.classList.add('cell-water');
    }

    // Visibility indicator
    if (visibleA && !visibleB) {
      cell.classList.add('visible-A');
    } else if (visibleB && !visibleA) {
      cell.classList.add('visible-B');
    } else {
      cell.classList.add('visible-both');
    }

    // Build tooltip
    const entityNames = {
      player_a: '玩家A',
      player_b: '玩家B',
      treasure: '宝箱',
      obstacle: '障碍物',
      exit: '出口',
    };

    cell.title = entities.length > 0
      ? entities.map(e => {
          const name = e.name || entityNames[e.type] || e.type || '未知';
          const playerSuffix = e.player ? ` (${e.player})` : '';
          return name + playerSuffix;
        }).join(', ')
      : (cellObj.terrain || '空地');

    // Render entities
    if (entities.length === 0) {
      cell.innerHTML = '<span style="color:#333">·</span>';
    } else {
      const entity = entities[0];
      const icon = entity.icon
        || { A: '🅰', B: '🅱' }[entity.player]
        || ({ player_a: '🅰', player_b: '🅱', treasure: '📦', obstacle: '🪨', exit: '🚪' }[entity.type])
        || '?';
      cell.innerHTML = `<span class="cell-icon">${icon}</span>`;

      if (entities.length > 1) {
        const badge = document.createElement('span');
        badge.className = 'cell-rule-indicator';
        badge.textContent = `×${entities.length}`;
        cell.appendChild(badge);
      }
    }
  }

  /** Highlight cells that are currently reachable */
  highlightReachable(reachableSet) {
    const cells = this.grid.children;
    for (let y = 0; y < this.state.height; y++) {
      for (let x = 0; x < this.state.width; x++) {
        const cell = cells[y * this.state.width + x];
        cell.classList.remove('reachable');
      }
    }
    for (const key of reachableSet) {
      const [x, y] = key.split(',').map(Number);
      const cell = cells[y * this.state.width + x];
      if (cell) cell.classList.add('reachable');
    }
  }
}"}

write_file:{"path":"src/ui/RevealSystem.js","content":"import { PLAYER } from '../game/constants.js';

/**
 * RevealSystem handles the fog-of-war reveal mechanic.
 * A player reveals the cell they stand on and adjacent cells.
 */
export class RevealSystem {
  constructor(gameState) {
    this.state = gameState;
  }

  /**
   * Reveal the cell (x, y) and its four orthogonal neighbors to the given player.
   */
  reveal(player, x, y) {
    const changed = [];
    // Reveal center
    this.state.revealTo(player, x, y);
    changed.push(`${x},${y}`);

    // Reveal adjacent (orthogonal)
    const adjacents = [
      [x, y - 1], [x, y + 1], [x - 1, y], [x + 1, y]
    ];
    for (const [ax, ay] of adjacents) {
      if (ax >= 0 && ax < this.state.width &&
          ay >= 0 && ay < this.state.height) {
        this.state.revealTo(player, ax, ay);
        changed.push(`${ax},${ay}`);
      }
    }

    return changed;
  }

  /**
   * Get a summary of what was newly revealed on a cell.
   * Returns array of entity descriptions.
   */
  getRevealedEntities(x, y, player) {
    const cell = this.state.grid.cells[y][x];
    if (!cell) return [];
    const entities = cell.entities || [];
    return entities.map(e => ({
      type: e.type,
      player: e.player || null,
      name: e.name || null,
    }));
  }

  /**
   * Get all cells revealed to a player.
   */
  getRevealedCells(player) {
    const revealed = [];
    for (let y = 0; y < this.state.height; y++) {
      for (let x = 0; x < this.state.width; x++) {
        if (this.state.isRevealedTo(x, y, player)) {
          revealed.push({ x, y });
        }
      }
    }
    return revealed;
  }
}"}

write_file:{"content":"import { DIRECTION, PLAYER } from './constants.js';

/**
 * GameEngine handles movement rules, collision detection,
 * and win/loss conditions.
 */
export class GameEngine {
  constructor(gameState) {
    this.state = gameState;
  }

  /**
   * Attempt to move a player in a direction.
   * Returns { success, message, events } where events is an array of
   * { type: 'move'|'reveal'|'pickup'|'win'|'lose', ... }.
   */
  movePlayer(player, direction) {
    const playerKey = `player_${player.toLowerCase()}`;
    const pos = this.state.getPlayerPosition(player);
    if (!pos) return { success: false, message: '玩家未找到', events: [] };

    const { x, y } = pos;
    let nx = x;
    let ny = y;

    switch (direction) {
      case DIRECTION.UP:    ny = y - 1; break;
      case DIRECTION.DOWN:  ny = y + 1; break;
      case DIRECTION.LEFT:  nx = x - 1; break;
      case DIRECTION.RIGHT: nx = x + 1; break;
      default: return { success: false, message: '无效方向', events: [] };
    }

    // Bounds check
    if (nx < 0 || nx >= this.state.width || ny < 0 || ny >= this.state.height) {
      return { success: false, message: '超出边界', events: [] };
    }

    // Terrain check
    const targetCell = this.state.grid.cells[ny][nx];
    if (targetCell.terrain === 'wall') {
      return { success: false, message: '撞到墙了', events: [] };
    }

    // Entity collision check
    const targetEntities = targetCell.entities || [];
    const blockingEntity = targetEntities.find(e => e.type === 'obstacle');
    if (blockingEntity) {
      return { success: false, message: '前方有障碍物', events: [] };
    }

    // Check for another player
    const otherPlayer = targetEntities.find(e =>
      e.type === 'player_a' || e.type === 'player_b'
    );
    if (otherPlayer) {
      return { success: false, message: '该格子已被其他玩家占据', events: [] };
    }

    // Move the player
    const events = [];
    const oldCell = this.state.grid.cells[y][x];

    // Remove player from old cell
    oldCell.entities = (oldCell.entities || []).filter(
      e => !(e.type === playerKey && e.player === player)
    );

    // Add player to new cell
    const playerEntity = {
      type: playerKey,
      player: player,
      name: player === PLAYER.A ? '玩家A' : '玩家B',
      icon: player === PLAYER.A ? '🅰' : '🅱',
    };
    if (!targetCell.entities) targetCell.entities = [];
    targetCell.entities.push(playerEntity);

    // Update player position in game state
    if (!this.state.playerPositions) {
      this.state.playerPositions = {};
    }
    this.state.playerPositions[player] = { x: nx, y: ny };

    events.push({ type: 'move', player, from: { x, y }, to: { x: nx, y: ny } });

    // Check for pickups (treasure)
    const treasureIdx = targetCell.entities.findIndex(e => e.type === 'treasure');
    if (treasureIdx >= 0) {
      targetCell.entities.splice(treasureIdx, 1);
      events.push({ type: 'pickup', player, item: 'treasure', x: nx, y: ny });

      // Check win condition
      const exitAtCell = targetCell.entities.find(e => e.type === 'exit');
      if (exitAtCell) {
        events.push({ type: 'win', player });
        return { success: true, message: `${playerEntity.name} 获胜！`, events };
      }
    }

    // Check if player walked into exit without treasure
    const exitAtCell = targetCell.entities.find(e => e.type === 'exit');
    if (exitAtCell && !events.some(e => e.type === 'pickup')) {
      events.push({
        type: 'message',
        text: '你需要先收集宝箱才能通过出口！',
      });
    }

    return { success: true, message: '移动成功', events };
  }

  /**
   * Get all valid moves for a player.
   * Returns array of { direction, x, y }.
   */
  getValidMoves(player) {
    const pos = this.state.getPlayerPosition(player);
    if (!pos) return [];

    const directions = [DIRECTION.UP, DIRECTION.DOWN, DIRECTION.LEFT, DIRECTION.RIGHT];
    const valid = [];

    for (const dir of directions) {
      let nx = pos.x;
      let ny = pos.y;
      switch (dir) {
        case DIRECTION.UP:    ny--; break;
        case DIRECTION.DOWN:  ny++; break;
        case DIRECTION.LEFT:  nx--; break;
        case DIRECTION.RIGHT: nx++; break;
      }

      if (nx < 0 || nx >= this.state.width || ny < 0 || ny >= this.state.height) continue;
      const cell = this.state.grid.cells[ny][nx];
      if (cell.terrain === 'wall') continue;
      const entities = cell.entities || [];
      if (entities.some(e => e.type === 'obstacle')) continue;
      if (entities.some(e => e.type === 'player_a' || e.type === 'player_b')) continue;

      valid.push({ direction: dir, x: nx, y: ny });
    }

    return valid;
  }

  /**
   * Check if a player has won.
   */
  checkWinCondition(player) {
    const pos = this.state.getPlayerPosition(player);
    if (!pos) return false;
    const cell = this.state.grid.cells[pos.y][pos.x];
    const entities = cell.entities || [];
    const hasTreasure = entities.some(e => e.type === 'treasure');
    const hasExit = entities.some(e => e.type === 'exit');
    return hasTreasure && hasExit;
  }

  /**
   * Get a movement direction based on player input.
   */
  static getDirectionFromKey(key, keyMap) {
    for (const [dir, keys] of Object.entries(keyMap)) {
      if (keys.includes(key)) return dir;
    }
    return null;
  }
}","path":"src/game/GameEngine.js"}

write_file:{"content":"import { GameState } from '../game/GameState.js';
import { GameEngine } from '../game/GameEngine.js';
import { getLevel } from '../game/Levels.js';
import { PLAYER, DIRECTION, ENTITY_TYPE } from '../game/constants.js';
import { BoardRenderer } from './BoardRenderer.js';
import { InputHandler } from './InputHandler.js';
import { RevealSystem } from './RevealSystem.js';
import { MessageLog } from './MessageLog.js';

/**
 * Main Game controller that orchestrates all components.
 */
export class Game {
  static PLAYER_NAMES = {
    [PLAYER.A]: '玩家A',
    [PLAYER.B]: '玩家B',
  };

  static DIR_NAMES = {
    [DIRECTION.UP]: '↑上',
    [DIRECTION.DOWN]: '↓下',
    [DIRECTION.LEFT]: '←左',
    [DIRECTION.RIGHT]: '→右',
  };

  constructor(containerEl, options = {}) {
    this.containerEl = containerEl;
    this.options = options;

    // UI elements
    this.boardEl = null;
    this.statusEl = null;
    this.rulesEl = null;
    this.messageLog = null;

    // Game state
    this.state = null;
    this.engine = null;
    this.renderer = null;
    this.inputHandler = null;
    this.revealSystem = null;

    // Turn management
    this.currentTurn = PLAYER.A;
    this.moveCount = 0;
    this.gameOver = false;
    this.winner = null;

    // Fog of war
    this.fogEnabled = options.fogOfWar !== false;

    this.init();
  }

  init() {
    this.buildUI();
    this.messageLog = new MessageLog(this.rulesEl);
    this.revealSystem = new RevealSystem();
    this.inputHandler = new InputHandler(this.handleInput.bind(this));

    // Load first level
    this.loadLevel(0);

    this.render();
    this.messageLog.add('游戏开始！玩家A先行动');
    this.updateStatus();
  }

  buildUI() {
    this.containerEl.innerHTML = `
      <div class="game-container">
        <div class="game-header">
          <h2>🗺️ 迷雾寻宝</h2>
          <div class="game-status" id="game-status"></div>
        </div>
        <div class="game-board-wrapper">
          <div id="game-board" class="game-board"></div>
        </div>
        <div class="game-info">
          <div class="rules-panel" id="rules-panel">
            <h4>📜 游戏日志</h4>
            <div id="message-log"></div>
          </div>
        </div>
      </div>
    `;

    this.boardEl = this.containerEl.querySelector('#game-board');
    this.statusEl = this.containerEl.querySelector('#game-status');
    this.rulesEl = this.containerEl.querySelector('#message-log');
  }

  loadLevel(levelIndex) {
    const levelData = getLevel(levelIndex);
    if (!levelData) {
      this.messageLog?.add?.('所有关卡已完成！');
      return false;
    }

    this.state = new GameState(levelData);
    this.engine = new GameEngine(this.state);
    this.renderer = new BoardRenderer(this.boardEl);
    this.revealSystem.reset();

    // Initial reveal around both players
    if (this.fogEnabled) {
      const posA = this.state.getPlayerPosition(PLAYER.A);
      const posB = this.state.getPlayerPosition(PLAYER.B);
      if (posA) this.revealSystem.revealAround(this.state, posA.x, posA.y, 2);
      if (posB) this.revealSystem.revealAround(this.state, posB.x, posB.y, 2);
    }

    this.moveCount = 0;
    this.gameOver = false;
    this.winner = null;
    this.currentTurn = PLAYER.A;

    return true;
  }

  handleInput(action) {
    if (this.gameOver) return;

    // Handle movement
    if (action.type === 'move') {
      this.handleMove(action.player, action.direction);
    }
    // Handle pass turn
    else if (action.type === 'pass') {
      this.handlePass(action.player);
    }
    // Handle special actions
    else if (action.type === 'peek') {
      this.handlePeek(action.player);
    }
  }

  handleMove(player, direction) {
    if (player !== this.currentTurn) {
      this.messageLog.add(`不是 ${Game.PLAYER_NAMES[player]} 的回合！`);
      return;
    }

    const result = this.engine.movePlayer(player, direction);

    if (result.success) {
      this.moveCount++;

      // Process events
      for (const event of result.events) {
        this.processEvent(event, player);
      }

      // Update fog of war
      if (this.fogEnabled) {
        const pos = this.state.getPlayerPosition(player);
        if (pos) {
          this.revealSystem.revealAround(this.state, pos.x, pos.y, 2);
        }
      }

      this.render();

      // Check game over
      if (this.gameOver) return;

      // Switch turns
      this.switchTurn();
    } else {
      this.messageLog.add(result.message);
    }

    this.updateStatus();
  }

  handlePass(player) {
    if (player !== this.currentTurn) {
      this.messageLog.add(`不是 ${Game.PLAYER_NAMES[player]} 的回合！`);
      return;
    }
    this.messageLog.add(`${Game.PLAYER_NAMES[player]} 跳过回合`);
    this.switchTurn();
    this.updateStatus();
  }

  handlePeek(player) {
    if (player !== this.currentTurn) {
      this.messageLog.add(`不是 ${Game.PLAYER_NAMES[player]} 的回合！`);
      return;
    }
    const pos = this.state.getPlayerPosition(player);
    if (pos && this.fogEnabled) {
      this.revealSystem.revealAround(this.state, pos.x, pos.y, 3);
      this.render();
      this.messageLog.add(`${Game.PLAYER_NAMES[player]} 使用侦查（扩大视野）`);
    }
    this.switchTurn();
    this.updateStatus();
  }

  processEvent(event, player) {
    switch (event.type) {
      case 'move':
        this.messageLog.add(
          `${Game.PLAYER_NAMES[player]} 移动到 (${event.to.x}, ${event.to.y})`
        );
        break;
      case 'pickup':
        this.messageLog.add(`${Game.PLAYER_NAMES[player]} 收集了宝箱！现在需要找到出口`);
        break;
      case 'win':
        this.gameOver = true;
        this.winner = player;
        this.messageLog.add(`🎉 ${Game.PLAYER_NAMES[player]} 获胜！`);
        break;
      case 'message':
        this.messageLog.add(event.text);
        break;
    }
  }

  switchTurn() {
    this.currentTurn = this.currentTurn === PLAYER.A ? PLAYER.B : PLAYER.A;
    this.messageLog.add(`轮到 ${Game.PLAYER_NAMES[this.currentTurn]} 行动`);
  }

  updateStatus() {
    if (!this.statusEl) return;

    if (this.gameOver) {
      this.statusEl.innerHTML = `
        <div class="status-win">🏆 ${Game.PLAYER_NAMES[this.winner]} 获胜！</div>
        <div class="status-moves">总步数: ${this.moveCount}</div>
      `;
    } else {
      const posA = this.state.getPlayerPosition(PLAYER.A);
      const posB = this.state.getPlayerPosition(PLAYER.B);

      this.statusEl.innerHTML = `
        <div class="status-turn ${this.currentTurn === PLAYER.A ? 'active-a' : ''}">
          当前回合: ${Game.PLAYER_NAMES[this.currentTurn]}
        </div>
        <div class="status-players">
          <span>🅰 ${posA ? `(${posA.x},${posA.y})` : '未部署'}</span>
          <span>🅱 ${posB ? `(${posB.x},${posB.y})` : '未部署'}</span>
        </div>
        <div class="status-moves">步数: ${this.moveCount}</div>
      `;
    }
  }

  render() {
    if (!this.renderer || !this.state) return;

    this.renderer.render(this.state, {
      fogEnabled: this.fogEnabled,
      revealedCells: this.revealSystem.getRevealedCells(),
      highlightPlayer: this.currentTurn,
    });
  }

  destroy() {
    if (this.inputHandler) {
      this.inputHandler.destroy();
    }
    this.containerEl.innerHTML = '';
  }
}","path":"src/ui/Game.js"}

write_file:{"path":"src/ui/Game.js","content":"/**
 * Game - UI orchestrator that wires together BoardRenderer, InputHandler,
 * RevealSystem, MessageLog, GameState, GameEngine, and Level loading.
 *
 * All modules are imported and composed here. The Game class owns the
 * top-level game loop (init → input → engine → reveal → render → log).
 */
import { PLAYER, DIRECTION } from '../game/constants.js';
import { GameState } from '../game/GameState.js';
import { GameEngine } from '../game/GameEngine.js';
import { getLevel } from '../game/Levels.js';
import { BoardRenderer } from './BoardRenderer.js';
import { RevealSystem } from './RevealSystem.js';
import { MessageLog } from './MessageLog.js';
import { InputHandler } from './InputHandler.js';

const PLAYER_NAMES = { [PLAYER.A]: '玩家A', [PLAYER.B]: '玩家B' };
const DIR_NAMES = {
  [DIRECTION.UP]: '上',
  [DIRECTION.DOWN]: '下',
  [DIRECTION.LEFT]: '左',
  [DIRECTION.RIGHT]: '右',
};

export class Game {
  constructor() {
    // Core state & engine
    this.state = null;
    this.engine = null;

    // UI subsystems (created once DOM is ready)
    this.renderer = null;
    this.reveal = null;
    this.log = null;
    this.input = null;

    // Current level
    this.currentLevel = 0;

    // Turn control (alternating or free‑move)
    this.turn = PLAYER.A;
    this.winner = null;
    this.movesThisTurn = 0;
    this.maxMovesPerTurn = 1;
  }

  // ─── Initialisation ─────────────────────────────────────────────

  /**
   * Bootstrap the entire game: load level 0, create UI subsystems,
   * hook up keyboard listeners, and render the first frame.
   */
  init() {
    this.state = new GameState(20, 15);
    this.engine = new GameEngine(this.state);

    this.renderer = new BoardRenderer(this.state);
    this.reveal = new RevealSystem(this.state);
    this.log = new MessageLog('log-container');

    // InputHandler needs the key‑maps defined in its module; we just
    // instantiate it, then subscribe to direction events.
    this.input = new InputHandler();
    this.input.onDirection((player, direction) => {
      if (this.winner) return; // game over
      if (player !== this.turn) {
        this.log.add(`现在不是 ${PLAYER_NAMES[player]} 的回合`, 'warning');
        return;
      }
      this._executeMove(player, direction);
    });

    this.input.bind();

    this._loadLevel(this.currentLevel);
    this._initialReveal();
    this.renderer.createGrid('board-container');
    this._updateHUD();

    this.log.add('🔰 双盲迷宫 – 玩家A 先手！使用 WASD / 方向键移动', 'system');
  }

  // ─── Level management ───────────────────────────────────────────

  _loadLevel(index) {
    const level = getLevel(index);
    if (!level) {
      this.log.add('🎉 你已完成所有关卡！', 'win');
      this.winner = 'done';
      return;
    }

    this.state.width = level.width;
    this.state.height = level.height;
    this.state.grid.cells = level.cells; // Level provides fully‑built cells

    // Place players at their start positions
    this.state.players[PLAYER.A] = { ...level.startA };
    this.state.players[PLAYER.B] = { ...level.startB };

    // Re‑stamp player entities into the grid cells
    this._placePlayerEntity(PLAYER.A, level.startA.x, level.startA.y);
    this._placePlayerEntity(PLAYER.B, level.startB.x, level.startB.y);

    this.turn = PLAYER.A;
    this.movesThisTurn = 0;
    this.winner = null;
  }

  _placePlayerEntity(player, x, y) {
    const cell = this.state.grid.cells[y][x];
    if (!cell.entities) cell.entities = [];
    // Remove old occurrences of this player (if any)
    cell.entities = cell.entities.filter(
      e => e.type !== `player_${player.toLowerCase()}`
    );
    cell.entities.push({
      type: `player_${player.toLowerCase()}`,
      player,
      name: PLAYER_NAMES[player],
      icon: player === PLAYER.A ? '🅰' : '🅱',
    });
  }

  // ─── Reveal helpers ─────────────────────────────────────────────

  _initialReveal() {
    for (const p of [PLAYER.A, PLAYER.B]) {
      const pos = this.state.players[p];
      this.reveal.reveal(p, pos.x, pos.y);
    }
  }

  _revealAround(player) {
    const pos = this.state.players[player];
    this.reveal.reveal(player, pos.x, pos.y);
  }

  // ─── Move execution ─────────────────────────────────────────────

  _executeMove(player, direction) {
    const result = this.engine.movePlayer(player, direction);
    if (!result.success) {
      this.log.add(result.message, 'error');
      return;
    }

    // Engine already mutated GameState – now sync the players ref
    // (engine writes to this.state.playerPositions, but we also
    //  keep this.state.players in sync just to be safe.)
    if (this.state.playerPositions) {
      this.state.players[player] = {
        ...this.state.playerPositions[player],
      };
    }

    // Reveal new cell + neighbours
    this._revealAround(player);

    // Process events produced by the engine
    for (const evt of result.events) {
      switch (evt.type) {
        case 'move':
          this.log.add(
            `${PLAYER_NAMES[player]} 向${DIR_NAMES[direction]}移动 ` +
            `(${evt.from.x},${evt.from.y}) → (${evt.to.x},${evt.to.y})`,
            'move'
          );
          break;
        case 'pickup':
          this.log.add(`${PLAYER_NAMES[player]} 获得了宝箱！`, 'pickup');
          break;
        case 'win':
          this.winner = player;
          this.log.add(`🏆 ${PLAYER_NAMES[player]} 获胜！`, 'win');
          break;
        case 'message':
          this.log.add(evt.text, 'info');
          break;
      }
    }

    // Re‑render board
    this.renderer.createGrid('board-container');

    // Advance turn (if no winner yet)
    if (!this.winner) {
      this._advanceTurn(player);
    }

    this._updateHUD();
  }

  _advanceTurn(player) {
    this.movesThisTurn++;
    if (this.movesThisTurn >= this.maxMovesPerTurn) {
      this.movesThisTurn = 0;
      this.turn = this.turn === PLAYER.A ? PLAYER.B : PLAYER.A;
      this.log.add(`轮到 ${PLAYER_NAMES[this.turn]}`, 'info');
    }
  }

  // ─── HUD ────────────────────────────────────────────────────────

  _updateHUD() {
    const hudEl = document.getElementById('hud');
    if (!hudEl) return;

    const posA = this.state.players[PLAYER.A];
    const posB = this.state.players[PLAYER.B];

    hudEl.innerHTML =
      `<span>🧭 玩家A (${posA.x},${posA.y})</span>` +
      `<span>🧭 玩家B (${posB.x},${posB.y})</span>` +
      `<span style="color:${this.turn === PLAYER.A ? '#4af' : '#f84'}">` +
      `⏳ 当前回合: ${PLAYER_NAMES[this.turn]}</span>` +
      (this.winner
        ? `<span style="color:gold">🏆 ${PLAYER_NAMES[this.winner]} 赢了！按 R 重开</span>`
        : '');
  }

  // ─── Reset ──────────────────────────────────────────────────────

  reset() {
    this._loadLevel(this.currentLevel);
    this._initialReveal();
    this.renderer.createGrid('board-container');
    this._updateHUD();
    this.winner = null;
    this.log.add('🔄 重新开始', 'system');
  }

  /**
   * Hot‑swap level (called from UI or console).
   */
  loadLevel(index) {
    this.currentLevel = index;
    this.reset();
  }
}"}

write_file:{"path":"src/game/GameState.js","content":"/**
 * 游戏状态管理器 - 双盲模式
 *
 * Holds the grid, player positions, and visibility state.
 * Mutated directly by GameEngine and RevealSystem (trusted neighbours).
 */
import { PLAYER } from './constants.js';

export class GameState {
  constructor(width = 20, height = 15) {
    this.width = width;
    this.height = height;

    // Player positions (canonical source of truth)
    this.players = {
      [PLAYER.A]: { x: 0, y: 0 },
      [PLAYER.B]: { x: 0, y: 0 },
    };

    // Grid: cells[y][x] = { terrain, entities[], revealedTo[], rules[] }
    this.grid = {
      width,
      height,
      cells: this._createEmptyGrid(width, height),
    };

    // Ephemeral alias used by GameEngine after moves – kept for backward compat
    this.playerPositions = null;
  }

  // ─── Helpers ────────────────────────────────────────────────────

  _createEmptyGrid(w, h) {
    const cells = [];
    for (let y = 0; y < h; y++) {
      cells[y] = [];
      for (let x = 0; x < w; x++) {
        cells[y][x] = {
          terrain: 'floor',
          entities: [],
          revealedTo: [],
          rules: [],
        };
      }
    }
    return cells;
  }

  /**
   * Get a player's current position.
   * Used by GameEngine.movePlayer().
   */
  getPlayerPosition(player) {
    // Prefer the playerPositions shadow (set by engine after a move),
    // then fall back to our primary players map.
    if (this.playerPositions && this.playerPositions[player]) {
      return this.playerPositions[player];
    }
    return this.players[player] || null;
  }

  /**
   * Check whether a cell (x,y) has been revealed to a specific player.
   */
  isRevealedTo(player, x, y) {
    if (x < 0 || x >= this.width || y < 0 || y >= this.height) return false;
    const cell = this.grid.cells[y][x];
    return cell.revealedTo && cell.revealedTo.includes(player);
  }

  /**
   * Mark a cell as revealed for a player.
   */
  revealTo(player, x, y) {
    if (x < 0 || x >= this.width || y < 0 || y >= this.height) return;
    const cell = this.grid.cells[y][x];
    if (!cell.revealedTo) cell.revealedTo = [];
    if (!cell.revealedTo.includes(player)) {
      cell.revealedTo.push(player);
    }
  }

  /**
   * Get entities at a position visible to a specific player.
   * Returns entities only if the cell is revealed to that player.
   */
  getVisibleEntities(player, x, y) {
    if (!this.isRevealedTo(player, x, y)) return [];
    const cell = this.grid.cells[y][x];
    return cell.entities || [];
  }

  /**
   * Deep‑ish clone of the current state (for save / undo – future use).
   */
  clone() {
    const copy = new GameState(this.width, this.height);
    copy.players = {
      [PLAYER.A]: { ...this.players[PLAYER.A] },
      [PLAYER.B]: { ...this.players[PLAYER.B] },
    };
    copy.grid.cells = this.grid.cells.map(row =>
      row.map(cell => ({
        terrain: cell.terrain,
        entities: [...(cell.entities || [])],
        revealedTo: [...(cell.revealedTo || [])],
        rules: [...(cell.rules || [])],
      }))
    );
    return copy;
  }
}"}

write_file:{"path":"src/game/GameEngine.js","content":"/**
 * GameEngine – processes player movements, collision detection,
 * event generation (move, pickup, win), and entity removal.
 *
 * Mutates the GameState directly (trusted companion).
 */
import { PLAYER, DIRECTION } from './constants.js';

export class GameEngine {
  constructor(state) {
    this.state = state;
  }

  /**
   * Attempt to move a player one step in the given direction.
   *
   * @param {string} player - PLAYER.A or PLAYER.B
   * @param {string} direction - DIRECTION.UP/DOWN/LEFT/RIGHT
   * @returns {{
   *   success: boolean,
   *   message: string,
   *   events: Array<{ type: string, [key: string]: any }>
   * }}
   */
  movePlayer(player, direction) {
    const pos = this.state.getPlayerPosition(player);
    if (!pos) {
      return {
        success: false,
        message: `无法获取 ${player} 的位置`,
        events: [],
      };
    }

    const { x, y } = pos;
    let nx = x;
    let ny = y;

    switch (direction) {
      case DIRECTION.UP:    ny--; break;
      case DIRECTION.DOWN:  ny++; break;
      case DIRECTION.LEFT:  nx--; break;
      case DIRECTION.RIGHT: nx++; break;
      default:
        return { success: false, message: '无效方向', events: [] };
    }

    // Bounds check
    if (nx < 0 || nx >= this.state.width || ny < 0 || ny >= this.state.height) {
      return { success: false, message: '撞墙了！边界', events: [] };
    }

    const fromCell = this.state.grid.cells[y][x];
    const toCell = this.state.grid.cells[ny][nx];

    // Terrain blocking
    if (toCell.terrain === 'wall') {
      return { success: false, message: '撞墙了！', events: [] };
    }

    // Remove player entity from old cell
    if (fromCell.entities) {
      fromCell.entities = fromCell.entities.filter(
        e => e.type !== `player_${player.toLowerCase()}`
      );
    }

    // Add player entity to new cell
    if (!toCell.entities) toCell.entities = [];
    toCell.entities.push({
      type: `player_${player.toLowerCase()}`,
      player,
      name: player === PLAYER.A ? '玩家A' : '玩家B',
      icon: player === PLAYER.A ? '🅰' : '🅱',
    });

    // Update position in state (both canonical and playerPositions shadow)
    this.state.players[player] = { x: nx, y: ny };
    if (!this.state.playerPositions) this.state.playerPositions = {};
    this.state.playerPositions[player] = { x: nx, y: ny };

    // Build events
    const events = [];
    events.push({ type: 'move', from: { x, y }, to: { x: nx, y: ny } });

    // Check for treasure
    const treasureIdx = toCell.entities.findIndex(
      e => e.type === 'treasure' || e.type === 'chest'
    );
    if (treasureIdx !== -1) {
      toCell.entities.splice(treasureIdx, 1);
      events.push({ type: 'pickup' });

      // Check if all treasures gone → win
      const remaining = this._countTreasures();
      if (remaining === 0) {
        events.push({ type: 'win' });
      }
    }

    // Check for exit / goal cell
    const hasExit = toCell.entities.some(
      e => e.type === 'exit' || e.type === 'goal'
    );
    if (hasExit) {
      events.push({ type: 'win' });
    }

    return { success: true, message: '', events };
  }

  /** Count remaining treasure/chest entities across the whole grid. */
  _countTreasures() {
    let count = 0;
    for (let y = 0; y < this.state.height; y++) {
      for (let x = 0; x < this.state.width; x++) {
        const cell = this.state.grid.cells[y][x];
        if (cell.entities) {
          count += cell.entities.filter(
            e => e.type === 'treasure' || e.type === 'chest'
          ).length;
        }
      }
    }
    return count;
  }
}
"}

write_file:{"path":"index.html","content":"<!DOCTYPE html>
<html lang="zh-CN">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Dungeon Explorer - 双人地牢探索</title>
  <style>
    *,
    *::before,
    *::after {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    :root {
      --bg-primary: #1a1a2e;
      --bg-secondary: #16213e;
      --bg-tertiary: #0f3460;
      --text-primary: #e0e0e0;
      --text-secondary: #a0a0a0;
      --accent-a: #ff6b6b;
      --accent-b: #4ecdc4;
      --accent-gold: #ffd93d;
      --border-color: #2a2a4a;
      --cell-size: 40px;
      --cell-gap: 2px;
      --fog-color: #1a1a2e;
      --revealed-color: #2a2a4a;
      --wall-color: #555;
      --floor-color: #333;
    }

    body {
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      background: #0d0d1a;
      color: var(--text-primary);
      min-height: 100vh;
      display: flex;
      justify-content: center;
      align-items: center;
      overflow-x: hidden;
    }

    #app {
      width: 100%;
      max-width: 1200px;
      padding: 20px;
    }

    /* Header */
    .game-header {
      text-align: center;
      margin-bottom: 20px;
    }

    .game-header h1 {
      font-size: 2.2rem;
      font-weight: 700;
      background: linear-gradient(135deg, var(--accent-a), var(--accent-b));
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
      margin-bottom: 4px;
    }

    .game-header .subtitle {
      font-size: 0.85rem;
      color: var(--text-secondary);
      letter-spacing: 0.05em;
    }

    /* Main Layout */
    .game-layout {
      display: flex;
      gap: 20px;
      flex-wrap: wrap;
      justify-content: center;
      align-items: flex-start;
    }

    /* Left Panel - Controls & Info */
    .left-panel {
      flex: 0 0 280px;
      display: flex;
      flex-direction: column;
      gap: 16px;
    }

    /* Panel Cards */
    .panel-card {
      background: var(--bg-secondary);
      border: 1px solid var(--border-color);
      border-radius: 10px;
      padding: 16px;
    }

    .panel-card h3 {
      font-size: 0.9rem;
      text-transform: uppercase;
      letter-spacing: 0.1em;
      color: var(--text-secondary);
      margin-bottom: 12px;
      padding-bottom: 8px;
      border-bottom: 1px solid var(--border-color);
    }

    /* Player Status */
    .player-status {
      display: flex;
      flex-direction: column;
      gap: 10px;
    }

    .player-item {
      display: flex;
      align-items: center;
      gap: 10px;
      padding: 8px;
      border-radius: 6px;
      background: var(--bg-tertiary);
    }

    .player-dot {
      width: 14px;
      height: 14px;
      border-radius: 50%;
      flex-shrink: 0;
    }

    .player-dot.player-a {
      background: var(--accent-a);
      box-shadow: 0 0 8px var(--accent-a);
    }

    .player-dot.player-b {
      background: var(--accent-b);
      box-shadow: 0 0 8px var(--accent-b);
    }

    .player-info {
      font-size: 0.85rem;
      color: var(--text-primary);
    }

    .player-info .player-name {
      font-weight: 600;
    }

    .player-info .player-pos {
      font-size: 0.75rem;
      color: var(--text-secondary);
    }

    /* Key Bindings */
    .key-bindings {
      display: flex;
      flex-direction: column;
      gap: 8px;
    }

    .key-group {
      padding: 6px 0;
    }

    .key-group-title {
      font-weight: 600;
      font-size: 0.8rem;
      margin-bottom: 4px;
    }

    .key-group-title.player-a-title {
      color: var(--accent-a);
    }

    .key-group-title.player-b-title {
      color: var(--accent-b);
    }

    .key-row {
      display: flex;
      gap: 8px;
      font-size: 0.78rem;
      padding: 2px 0;
    }

    .key-tag {
      display: inline-block;
      background: var(--bg-tertiary);
      border: 1px solid var(--border-color);
      border-radius: 4px;
      padding: 2px 6px;
      font-family: 'Courier New', monospace;
      font-size: 0.75rem;
      min-width: 22px;
      text-align: center;
      color: var(--text-primary);
    }

    .key-desc {
      color: var(--text-secondary);
    }

    /* Legend */
    .legend-grid {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
    }

    .legend-item {
      display: flex;
      align-items: center;
      gap: 6px;
      font-size: 0.78rem;
      color: var(--text-secondary);
    }

    .legend-icon {
      font-size: 1.1rem;
      width: 20px;
      text-align: center;
    }

    /* Center Panel - Board */
    .center-panel {
      flex: 1 1 auto;
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 12px;
    }

    /* Board Container */
    #board-container {
      background: var(--bg-secondary);
      border: 2px solid var(--border-color);
      border-radius: 12px;
      padding: 16px;
      box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
    }

    #board {
      display: grid;
      gap: var(--cell-gap);
      user-select: none;
      -webkit-user-select: none;
    }

    .cell {
      width: var(--cell-size);
      height: var(--cell-size);
      border-radius: 4px;
      position: relative;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 18px;
      transition: background-color 0.15s ease;
    }

    .cell.fog {
      background: var(--fog-color);
      border: 1px solid #111;
    }

    .cell.revealed {
      background: var(--revealed-color);
      border: 1px solid var(--border-color);
    }

    .cell.wall {
      background: var(--wall-color);
      border: 1px solid #444;
    }

    .cell.wall::after {
      content: '■';
      color: #777;
      font-size: 14px;
    }

    .cell .entity-icon {
      z-index: 2;
      pointer-events: none;
    }

    .cell .player-a-icon {
      color: var(--accent-a);
      font-size: 22px;
      text-shadow: 0 0 6px var(--accent-a);
    }

    .cell .player-b-icon {
      color: var(--accent-b);
      font-size: 22px;
      text-shadow: 0 0 6px var(--accent-b);
    }

    .cell .treasure-icon {
      color: var(--accent-gold);
      font-size: 16px;
    }

    .cell .trap-icon {
      color: #ff4444;
      font-size: 16px;
    }

    .cell .exit-icon {
      color: #44ff44;
      font-size: 18px;
    }

    .cell .monster-icon {
      color: #ff8844;
      font-size: 16px;
    }

    .cell.both-players {
      box-shadow: inset 0 0 0 2px var(--accent-a), inset 0 0 0 4px var(--accent-b);
    }

    /* Level Info */
    #level-info {
      display: flex;
      gap: 20px;
      align-items: center;
      font-size: 0.85rem;
    }

    #level-info .level-name {
      font-weight: 600;
      color: var(--accent-gold);
    }

    #level-info .level-desc {
      color: var(--text-secondary);
      font-size: 0.78rem;
    }

    /* Turn Indicator */
    #turn-indicator {
      text-align: center;
      font-size: 0.85rem;
      color: var(--text-secondary);
      padding: 6px 12px;
      background: var(--bg-tertiary);
      border-radius: 20px;
      min-width: 120px;
    }

    #turn-indicator .turn-num {
      font-weight: 700;
      color: var(--text-primary);
    }

    /* Right Panel - Log & Actions */
    .right-panel {
      flex: 0 0 260px;
      display: flex;
      flex-direction: column;
      gap: 16px;
    }

    /* Message Log */
    #message-log {
      max-height: 350px;
      overflow-y: auto;
      display: flex;
      flex-direction: column;
      gap: 4px;
      font-size: 0.78rem;
    }

    #message-log::-webkit-scrollbar {
      width: 6px;
    }

    #message-log::-webkit-scrollbar-track {
      background: var(--bg-tertiary);
      border-radius: 3px;
    }

    #message-log::-webkit-scrollbar-thumb {
      background: var(--border-color);
      border-radius: 3px;
    }

    .log-entry {
      padding: 4px 8px;
      border-radius: 4px;
      border-left: 3px solid transparent;
      animation: fadeIn 0.2s ease;
    }

    @keyframes fadeIn {
      from {
        opacity: 0;
        transform: translateY(-4px);
      }
      to {
        opacity: 1;
        transform: translateY(0);
      }
    }

    .log-entry.system {
      border-left-color: var(--text-secondary);
      color: var(--text-secondary);
    }

    .log-entry.reveal {
      border-left-color: var(--accent-gold);
      color: var(--accent-gold);
    }

    .log-entry.win {
      border-left-color: #44ff44;
      color: #44ff44;
      font-weight: 700;
    }

    .log-entry.warning {
      border-left-color: #ff8844;
      color: #ff8844;
    }

    /* Buttons */
    .btn {
      display: inline-block;
      padding: 10px 16px;
      border: 1px solid var(--border-color);
      border-radius: 6px;
      background: var(--bg-tertiary);
      color: var(--text-primary);
      cursor: pointer;
      font-size: 0.85rem;
      font-family: inherit;
      transition: all 0.2s ease;
      text-align: center;
    }

    .btn:hover {
      background: #1a4a8a;
      border-color: #4a8acc;
    }

    .btn:active {
      transform: scale(0.97);
    }

    .btn.primary {
      background: var(--accent-a);
      border-color: var(--accent-a);
      color: #fff;
      font-weight: 600;
    }

    .btn.primary:hover {
      background: #ff5252;
    }

    .btn.secondary {
      background: var(--accent-b);
      border-color: var(--accent-b);
      color: #1a1a2e;
      font-weight: 600;
    }

    .btn.secondary:hover {
      background: #3dbdb5;
    }

    .btn-group {
      display: flex;
      gap: 8px;
      flex-wrap: wrap;
    }

    /* Modal Overlay */
    #modal-overlay {
      display: none;
      position: fixed;
      inset: 0;
      background: rgba(0, 0, 0, 0.7);
      z-index: 100;
      justify-content: center;
      align-items: center;
    }

    #modal-overlay.active {
      display: flex;
    }

    .modal {
      background: var(--bg-secondary);
      border: 2px solid var(--border-color);
      border-radius: 12px;
      padding: 32px;
      text-align: center;
      max-width: 450px;
      width: 90%;
    }

    .modal h2 {
      font-size: 1.5rem;
      margin-bottom: 12px;
    }

    .modal p {
      color: var(--text-secondary);
      margin-bottom: 20px;
      font-size: 0.9rem;
    }

    .modal .win-icon {
      font-size: 3rem;
      margin-bottom: 12px;
    }

    /* Level Select */
    #level-select {
      padding: 8px 12px;
      border: 1px solid var(--border-color);
      border-radius: 6px;
      background: var(--bg-tertiary);
      color: var(--text-primary);
      font-size: 0.85rem;
      cursor: pointer;
      font-family: inherit;
    }

    #level-select:focus {
      outline: none;
      border-color: var(--accent-b);
    }

    option {
      background: var(--bg-secondary);
      color: var(--text-primary);
    }

    /* Responsive */
    @media (max-width: 960px) {
      .game-layout {
        flex-direction: column;
        align-items: center;
      }

      .left-panel,
      .right-panel {
        flex: 1 1 auto;
        width: 100%;
        max-width: 500px;
      }

      :root {
        --cell-size: 32px;
      }
    }

    @media (max-width: 600px) {
      :root {
        --cell-size: 26px;
      }

      .game-header h1 {
        font-size: 1.4rem;
      }
    }
  </style>
</head>
<body>
  <div id="app">
    <!-- Header -->
    <header class="game-header">
      <h1>🏰 Dungeon Explorer</h1>
      <p class="subtitle">双人地牢探索 · 揭开迷雾 · 合作寻宝</p>
    </header>

    <!-- Game Layout -->
    <div class="game-layout">
      <!-- Left Panel -->
      <aside class="left-panel">
        <!-- Player Status -->
        <div class="panel-card">
          <h3>🎮 玩家状态</h3>
          <div class="player-status">
            <div class="player-item">
              <div class="player-dot player-a"></div>
              <div class="player-info">
                <div class="player-name" id="player-a-name">玩家 A</div>
                <div class="player-pos" id="player-a-pos">位置: —</div>
              </div>
            </div>
            <div class="player-item">
              <div class="player-dot player-b"></div>
              <div class="player-info">
                <div class="player-name" id="player-b-name">玩家 B</div>
                <div class="player-pos" id="player-b-pos">位置: —</div>
              </div>
            </div>
          </div>
        </div>

        <!-- Controls -->
        <div class="panel-card">
          <h3>⌨️ 键位说明</h3>
          <div class="key-bindings">
            <div class="key-group">
              <div class="key-group-title player-a-title">🔴 玩家 A</div>
              <div class="key-row">
                <span class="key-tag">W</span><span class="key-tag">A</span><span class="key-tag">S</span><span class="key-tag">D</span>
                <span class="key-desc">或 方向键 移动</span>
              </div>
              <div class="key-row">
                <span class="key-tag">Q</span> <span class="key-desc">揭示</span>
                <span class="key-tag">E</span> <span class="key-desc">等待</span>
              </div>
            </div>
            <div class="key-group">
              <div class="key-group-title player-b-title">🔵 玩家 B</div>
              <div class="key-row">
                <span class="key-tag">I</span><span class="key-tag">J</span><span class="key-tag">K</span><span class="key-tag">L</span>
                <span class="key-desc">移动</span>
              </div>
              <div class="key-row">
                <span class="key-tag">U</span> <span class="key-desc">揭示</span>
                <span class="key-tag">O</span> <span class="key-desc">等待</span>
              </div>
            </div>
            <div class="key-group">
              <div class="key-group-title">全局</div>
              <div class="key-row">
                <span class="key-tag">Ctrl</span>+<span class="key-tag">Z</span>
                <span class="key-desc">撤销</span>
              </div>
            </div>
          </div>
        </div>

        <!-- Legend -->
        <div class="panel-card">
          <h3>📋 图例</h3>
          <div class="legend-grid">
            <div class="legend-item"><span class="legend-icon">⬛</span> 未知</div>
            <div class="legend-item"><span class="legend-icon">■</span> 墙壁</div>
            <div class="legend-item"><span class="legend-icon" style="color:var(--accent-a)">●</span> 玩家 A</div>
            <div class="legend-item"><span class="legend-icon" style="color:var(--accent-b)">●</span> 玩家 B</div>
            <div class="legend-item"><span class="legend-icon">💎</span> 宝藏</div>
            <div class="legend-item"><span class="legend-icon">⚠️</span> 陷阱</div>
            <div class="legend-item"><span class="legend-icon">👹</span> 怪物</div>
            <div class="legend-item"><span class="legend-icon">🚪</span> 出口</div>
          </div>
        </div>
      </aside>

      <!-- Center Panel - Game Board -->
      <main class="center-panel">
        <div id="board-container">
          <div id="board"></div>
        </div>
        <div id="level-info">
          <span class="level-name" id="level-name">—</span>
          <span class="level-desc" id="level-desc"></span>
        </div>
        <div id="turn-indicator">
          回合: <span class="turn-num" id="turn-num">1</span>
        </div>

        <!-- Action Buttons -->
        <div class="btn-group">
          <select id="level-select" title="选择关卡">
            <option value="">— 选择关卡 —</option>
          </select>
          <button class="btn" id="btn-reset" title="重新开始当前关卡">🔄 重置</button>
          <button class="btn" id="btn-undo" title="撤销上一步 (Ctrl+Z)">↩ 撤销</button>
        </div>
        <div class="btn-group">
          <button class="btn primary" id="btn-reveal-a">🔍 玩家A揭示 (Q)</button>
          <button class="btn secondary" id="btn-reveal-b">🔍 玩家B揭示 (U)</button>
        </div>
      </main>

      <!-- Right Panel - Log & Rules -->
      <aside class="right-panel">
        <!-- Message Log -->
        <div class="panel-card">
          <h3>📜 消息日志</h3>
          <div id="message-log">
            <div class="log-entry system">欢迎来到地牢！揭开迷雾，找到宝藏吧！</div>
          </div>
          <button class="btn" id="btn-clear-log" style="margin-top:8px;width:100%;font-size:0.78rem;">清空日志</button>
        </div>

        <!-- Rules Reference -->
        <div class="panel-card" id="rules-panel">
          <h3>📖 规则</h3>
          <div id="rules-content" style="font-size:0.78rem;color:var(--text-secondary);line-height:1.5;">
            <p>🔹 两位玩家共享视野，协作探索地牢。</p>
            <p>🔹 <strong>WASD / 方向键</strong> 控制玩家 A。</p>
            <p>🔹 <strong>IJKL</strong> 控制玩家 B。</p>
